dashboard.definition:
{
  "title": "Icon Library Showcase \u2014 250 Icons",
  "description": "Comprehensive showcase of icon_library visualization settings: colors, backgrounds, glow, shadow, labels, alignment, rotation, drilldown, threshold colors, and combined effects.",
  "dataSources": {
    "ds_stub": {
      "type": "ds.test",
      "options": {
        "data": {
          "fields": [
            {
              "name": "stub"
            }
          ],
          "columns": [
            [
              "1"
            ]
          ]
        }
      },
      "name": "Stub for icon rendering"
    },
    "ds_thr_10": {
      "type": "ds.test",
      "options": {
        "data": {
          "fields": [
            {
              "name": "value"
            }
          ],
          "columns": [
            [
              "10"
            ]
          ]
        }
      },
      "name": "Threshold demo \u2014 value=10"
    },
    "ds_thr_35": {
      "type": "ds.test",
