      "type": "splunk.markdown",
      "options": {
        "markdown": "### Live Demo: Drilldown\nClick any of the four icons below. Each panel sets `selected_icon` via `drilldown.setToken`. The status panel underneath shows the captured `$selected_icon$` token. Required wiring: panel option `\"drilldown\": \"all\"` + `eventHandlers` with `\"key\": \"row.icon.value\"`.",
        "fontColor": "#E2E8F0",
        "backgroundColor": "transparent"
      }
    },
    "viz_drill_demo_security": {
      "type": "icon_library.icon_library",
      "dataSources": {
        "primary": "ds_drill_security"
      },
      "options": {
        "backgroundColor": "transparent",
        "icon_library.icon_library.iconColor": "#06B6D4",
        "icon_library.icon_library.bgShape": "circle",
        "icon_library.icon_library.bgColor": "#0F172A",
        "icon_library.icon_library.bgPadding": "16",
        "icon_library.icon_library.glow": "yes",
        "icon_library.icon_library.glowColor": "#06B6D4",
        "icon_library.icon_library.glowSize": "12",
        "drilldown": "all"
      },
      "eventHandlers": [
        {
          "type": "drilldown.setToken",
          "options": {
            "tokens": [
